// YouTube search -> keep snippet fields keyed by video id, and emit ONE item
// carrying the comma-joined id list for the stats call. Tolerates a failed
// search (returns an empty carrier so the branch degrades to 0, never crashes).
const res = ($input.first() && $input.first().json) || {};
const items = (res.items || []).filter(it => it && it.id && it.id.videoId);
const byId = {};
for (const it of items) {
  byId[it.id.videoId] = {
    title: (it.snippet.title || '').trim(),
    summary: (it.snippet.description || '').slice(0, 300),
    url: 'https://www.youtube.com/watch?v=' + it.id.videoId,
    source: 'youtube',
    published_at: it.snippet.publishedAt ? Date.parse(it.snippet.publishedAt) : null
  };
}
const ids = Object.keys(byId).slice(0, 50); // videos:list caps at 50 ids/call
return [{ json: { ids: ids.join(','), byId } }];

// (same as YT Tools IDs, for the how-to branch)
const res = ($input.first() && $input.first().json) || {};
const items = (res.items || []).filter(it => it && it.id && it.id.videoId);
const byId = {};
for (const it of items) {
  byId[it.id.videoId] = {
    title: (it.snippet.title || '').trim(),
    summary: (it.snippet.description || '').slice(0, 300),
    url: 'https://www.youtube.com/watch?v=' + it.id.videoId,
    source: 'youtube',
    published_at: it.snippet.publishedAt ? Date.parse(it.snippet.publishedAt) : null
  };
}
const ids = Object.keys(byId).slice(0, 50);
return [{ json: { ids: ids.join(','), byId } }];

// Merge view stats back onto the search snippets (by video id) and emit a
// normalized candidate list with a real viewCount (engagement = views).
// $json is the stats response; the snippets are on the IDs node output.
const stats = ($input.first() && $input.first().json) || {};
const byViews = {};
for (const v of (stats.items || [])) {
  const n = v && v.statistics ? Number(v.statistics.viewCount) : NaN;
  byViews[v.id] = isFinite(n) ? n : 0;
}
// Pull the snippet map from the IDs node (same branch, upstream).
let byId = {};
try { byId = $('Code - YT Tools IDs').first().json.byId || {}; } catch (e) { byId = {}; }
const candidates = Object.keys(byId).map(id => ({
  ...byId[id],
  engagement: byViews[id] || 0,   // real YouTube views
  view_count: byViews[id] || 0
}));
return [{ json: { candidates } }];

// (same as Normalize YouTube Tools, for the how-to branch)
const stats = ($input.first() && $input.first().json) || {};
const byViews = {};
for (const v of (stats.items || [])) {
  const n = v && v.statistics ? Number(v.statistics.viewCount) : NaN;
  byViews[v.id] = isFinite(n) ? n : 0;
}
let byId = {};
try { byId = $('Code - YT How-To IDs').first().json.byId || {}; } catch (e) { byId = {}; }
const candidates = Object.keys(byId).map(id => ({
  ...byId[id],
  engagement: byViews[id] || 0,
  view_count: byViews[id] || 0
}));
return [{ json: { candidates } }];

// Reddit /hot.json -> normalized candidate list.
// Tolerates a failed/blocked Reddit call (returns an empty list instead of crashing).
const res = ($input.first() && $input.first().json) || {};
const children = (res.data && res.data.children) || [];
const candidates = children
  .map(c => c.data)
  .filter(Boolean)
  .map(d => ({
    title: (d.title || '').trim(),
    summary: (d.selftext || '').slice(0, 300),
    url: 'https://www.reddit.com' + (d.permalink || ''),
    source: 'reddit',
    engagement: (d.ups || 0) + (d.num_comments || 0),
    view_count: null,
    published_at: d.created_utc ? d.created_utc * 1000 : null
  }));
return [{ json: { candidates } }];

// RSS feed items -> normalized candidate list
const items = $input.all();
const candidates = items
  .map(i => i.json)
  .filter(Boolean)
  .map(a => ({
    title: (a.title || '').trim(),
    summary: (a.contentSnippet || a.content || '').slice(0, 300),
    url: a.link || '',
    source: 'news',
    engagement: 0,
    view_count: null,
    published_at: (a.isoDate || a.pubDate) ? Date.parse(a.isoDate || a.pubDate) : null
  }));
return [{ json: { candidates } }];

// Collapse the sheet rows into ONE item { existing_topics: [...] } for the
// scorer's cross-run dedupe (so re-running the finder never re-appends the
// same topics). Defensive: any unexpected shape -> empty list, dedupe just
// degrades gracefully instead of crashing the run.
const topics = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const t = j['Topic'] != null ? String(j['Topic']).trim() : '';
  if (t) topics.push(t);
}
return [{ json: { existing_topics: topics } }];

// AI-how-to-fit scoring + freshness + VIEW-COUNT gate + cross-run dedupe.
//
// THE NICHE -- enforced as HARD GATES, not score bonuses:
//   Every topic must teach ONE concrete, usable thing about an AI tool:
//   how to use it, a prompt trick, or which AI tool is best for a task.
//   - TOOL gate:   must mention an AI tool / product
//   - ACTION gate: must have a "here's what you can DO" angle -- pure
//     announcement headlines with nothing to try are dropped
//   - OFF gate:    finance/crypto, politics/legal, layoffs, motivation,
//     make-money/hustle, nsfw, tools nobody can access yet -> hard drop
//
// VIEW-COUNT gate (YouTube only): a YouTube candidate must have >= MIN_VIEWS
// real views to qualify -- proves the video actually converts. Non-YouTube
// sources (news/reddit) have no view metric and are exempt from this gate.
//
// FRESHNESS: anything older than MAX_AGE_DAYS is dropped (when dated); newer
// topics get a score bonus and win ties.
//
// CROSS-RUN DEDUPE: topics already on the Reels tab (any Status) are skipped
// BEFORE the top-N cut, so re-running finds NEXT-best fresh topics instead of
// re-appending. Same topic = exact/reorder match, OR high token overlap where
// the only differing words are generic filler (reword/year-swap). A differing
// CONTENT word ('emails' vs 'reports') keeps them distinct -- so real new
// topics are never wrongly dropped. The hard "never the same topic twice" rule.
//   The sheet list arrives via Merge input 5 as { existing_topics: [...] }.

const TOP_N = 5;
const MAX_AGE_DAYS = 7;
const MIN_SCORE = 7;
const MIN_VIEWS = 5000;        // YouTube view floor -- proven-traction bar
const DEDUPE_OVERLAP = 0.72;   // high-overlap TRIGGER; a fuzzy match ALSO
// requires every differing word to be generic filler (see overlaps). So two
// titles that differ by a real content word ('emails' vs 'reports', 'video'
// vs 'photo') stay DISTINCT even at high overlap, while pure rewords /
// reorders / year-swaps ('best...2026...today' vs 'best...2026') dedupe.

// ---- split the sheet's existing topics from the source candidates ----
const all = [];
let existing = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (Array.isArray(j.existing_topics)) { existing = existing.concat(j.existing_topics); continue; }
  for (const c of (j.candidates || [])) all.push(c);
}

// ---- niche gates ----
const TOOL = /(\bai\b|chatgpt|\bgpt\b|claude|gemini|grok|midjourney|sora|perplexity|notion ?ai|zapier|n8n|copilot|\bllm\b|ai agent|prompt|automation|deepseek|runway|elevenlabs|heygen|cursor|windsurf|lovable|bolt\.new|\bveo\b|nano ?banana|comfyui|stable diffusion|\bflux\b|suno|kling|luma|pika)/i;
const ACTION = /(how to|how i\b|tutorial|guide|step[- ]by[- ]step|\bus(e|es|ed|ing)\b|set ?up|build|built|create|automate|workflow|hack|trick|\btips?\b|prompt|best |top \d|\bvs\.?\b|versus|compar(e|ison|ed)|you can now|now you can|lets you|in \d+ ?(minutes?|mins?|seconds?|secs?)|without cod(e|ing)|for free\b)/i;
const NUM = /(\d+\s?(ai\s?)?tools?|\d+\s?%|in\s?\d+\s?(min|minute|sec|second|hour|day)|\btop\s?\d+\b|\d+x\b)/i;
const OFF = /(stock(s| market)?|crypto|bitcoin|ethereum|\bnft\b|invest|trading|trader|\bipo\b|raise[sd] \$|funding|valuation|acqui(res?|sition)|merger|lawsuit|sues?\b|court|antitrust|regulat|senate|congress|election|politic|tariff|layoffs?|motivat|mindset|hustle|get rich|millionaire|passive income|make (money|\$)|making money|\$\d+\s?(k|per|\/|a )|\d+\s?(k|dollars?)\s?(\/|per|a )\s?(mo|month|day|week)|side hustle|earn \$|nsfw|onlyfans|ai (girlfriend|boyfriend)|waifu|waitlist|coming soon|invite[- ]only|sneak peek|teaser)/i;
// JUNK gate: high-view but low-quality YouTube noise -- hashtag spam,
// non-English tutorials, cartoon/meme edits, engagement-bait titles. These
// pass niche+views but are NOT clean AI-skill content for our audience.
const JUNK = /(#\w|kaise banaye|kaise kare|banaye|dekho|\bviral\b|#shorts|shortsfeed|foryou|subscriber|1million|motu patlu|cartoon|meme|vlog|status video|\bwhatsapp\b|\bhindi\b|\burdu\b|\bbangla\b|prank|\blive test\b|gone wrong|you won'?t believe|shocking|\bomg\b)/i;
// A pile of hashtags (>=2) is a spam signal on its own.
function hashtagSpam(t) { return ((t || '').match(/#/g) || []).length >= 2; }

function blobOf(c) { return ((c.title || '') + ' ' + (c.summary || '')).toLowerCase(); }
function passesNiche(c) {
  const blob = blobOf(c);
  if (!TOOL.test(blob) || !ACTION.test(blob) || OFF.test(blob)) return false;
  // JUNK/hashtag-spam only applies to YouTube (news/reddit titles are clean).
  if (c.source === 'youtube' && (JUNK.test(blob) || hashtagSpam(c.title))) return false;
  return true;
}
function passesViews(c) {
  // Only YouTube carries a view metric; other sources are exempt.
  if (c.source !== 'youtube') return true;
  return Number(c.view_count || 0) >= MIN_VIEWS;
}

// ---- freshness ----
function ageDays(c) {
  if (!c.published_at || !isFinite(c.published_at)) return null;
  return (Date.now() - c.published_at) / 86400000;
}
function ageLabel(c) {
  const a = ageDays(c);
  if (a === null) return '?';
  return a < 1 ? Math.max(1, Math.round(a * 24)) + 'h' : Math.round(a) + 'd';
}
function viewsLabel(n) {
  if (!n) return '';
  if (n >= 1000000) return (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
  if (n >= 1000) return Math.round(n / 1000) + 'K';
  return String(n);
}

// ---- self-promo signal (ads that look like best-tool content) ----
const PROMO = /(see what .* can do for you|introducing |official (trailer|video|launch)|sponsored|get started (free|today) with)/i;

// ---- scoring (ranking only -- the gates above decide in/out) ----
function score(c) {
  const t = (c.title || '').trim();
  const blob = blobOf(c);
  const words = t.split(/\s+/).filter(Boolean).length;
  let s = 6; // TOOL + ACTION gates passed
  if (words >= 3 && words <= 16) s += 2;
  if (NUM.test(blob)) s += 2;
  if (words <= 12) s += 1;
  // View-count ranking: more real views -> higher (YouTube only).
  const v = Number(c.view_count || 0);
  if (v >= 500000) s += 3;
  else if (v >= 100000) s += 2;
  else if (v >= 20000) s += 1;
  const a = ageDays(c);
  if (a !== null && a <= 2) s += 2;
  else if (a !== null && a <= 4) s += 1;
  if (PROMO.test(blob)) s -= 4;
  return s;
}

// ---- dedupe: exact normalized key + word-overlap fuzzy match ----
const STOP = new Set(['the','a','an','to','for','of','in','on','with','and','or','is','are','your','you','this','that','it','its','my','how','what','why','from','into','2025','2026','new','best','top']);
function norm(s) { return (s || '').toLowerCase().replace(/[^a-z0-9 ]+/g, ' ').replace(/\s+/g, ' ').trim(); }
function tokens(s) { return new Set(norm(s).split(' ').filter(w => w.length > 2 && !STOP.has(w))); }
// Generic filler: words that reword a title without changing its TOPIC. If two
// high-overlap titles differ ONLY by these, they are the same topic reworded.
// Any OTHER differing word is a real content noun -> distinct topic, keep both.
const FILLER = new Set(['use','uses','used','using','guide','tutorial','complete','full','easy','quick','fast','simple','way','ways','today','now','week','method','tip','tips','trick','tricks','hack','hacks','should','try','tried','them','all','free','course','beginner','beginners','ultimate','make','making','create','creating','build','building','learn','learning','step','steps','crash','2024','using']);
function overlaps(aTok, bTok) {
  if (!aTok.size || !bTok.size) return false;
  let inter = 0;
  for (const w of aTok) if (bTok.has(w)) inter++;
  const ratio = inter / Math.min(aTok.size, bTok.size);
  if (ratio < DEDUPE_OVERLAP) return false;
  // High overlap -> a dup ONLY if every differing word is generic filler.
  for (const w of aTok) if (!bTok.has(w) && !FILLER.has(w)) return false;
  for (const w of bTok) if (!aTok.has(w) && !FILLER.has(w)) return false;
  return true;
}
const existingKeys = new Set(existing.map(norm));
const existingToks = existing.map(tokens);
const seenKeys = new Set();
const seenToks = [];
function isDup(title) {
  const k = norm(title);
  if (!k) return true; // empty title -> treat as dup (drop)
  if (seenKeys.has(k) || existingKeys.has(k)) return true;
  const tk = tokens(title);
  for (const et of existingToks) if (overlaps(tk, et)) return true;
  for (const st of seenToks) if (overlaps(tk, st)) return true;
  seenKeys.add(k);
  seenToks.push(tk);
  return false;
}

// ---- pipeline: fresh -> views -> on-niche -> scored -> best-first -> deduped top N ----
const scored = all
  .filter(c => c && c.title && c.title.length > 12)
  .filter(c => { const a = ageDays(c); return a === null || a <= MAX_AGE_DAYS; })
  .filter(passesViews)
  .filter(passesNiche)
  .map(c => ({ ...c, reel_fit: score(c), age_label: ageLabel(c), views_label: viewsLabel(Number(c.view_count || 0)) }))
  .filter(c => c.reel_fit >= MIN_SCORE)
  .sort((x, y) => y.reel_fit - x.reel_fit || Number(y.view_count || 0) - Number(x.view_count || 0) || (y.published_at || 0) - (x.published_at || 0));

const picked = [];
for (const c of scored) {
  if (picked.length >= TOP_N) break;
  if (!isDup(c.title)) picked.push(c);
}

if (picked.length === 0) {
  return [{ json: { skip: true, title: 'NO_AI_TOPICS' } }];
}
return picked.map(c => ({ json: c }));

// Build a BARE Reels-tab row per surviving candidate.
//
// This finder ONLY finds topics. It writes the MINIMUM (Topic + Key Points +
// Brand Tone) and does NO media-finding, NO YouTube-replacement, NO caption
// writing -- all of that is the builder's (Workflow B) job, done later on its
// own copy of the row. So the two automations never touch the same fields and
// can't crash each other.
//
// State: Status='Draft'. The builder ONLY fires on 'Ready to Run', so a Draft
// is ignored until the user reviews the 5 topics and flips the good ones to
// 'Ready to Run' by hand. This is the review gate -- the finder can never
// trigger an unwanted build.

const BRAND_TONE = 'Gen Z AI-native energy. Practical, fast, no hype. Teaches young people how to actually use AI tools to work faster and smarter. Bold, direct, neon-green aesthetic, zero fluff. Every video leaves the viewer with something they can use today.';

return $input.all().map(item => {
  const c = item.json;
  // Turn the raw candidate title into a clean topic string. Keep it short.
  let topic = (c.title || '').trim().replace(/\s+/g, ' ');
  // Strip common clickbait prefixes/emoji-ish noise from source titles.
  topic = topic.replace(/^[^A-Za-z0-9]+/, '').slice(0, 90).trim();

  const keyPoints = (c.summary || '').toString().slice(0, 200).trim()
    || 'Teach the viewer one concrete, usable AI trick from this topic.';

  const views = c.views_label ? ` views=${c.views_label}` : '';
  return {
    json: {
      'Topic': topic,
      'Key Points': keyPoints,
      'Brand Tone': BRAND_TONE,
      'Enriched Context': `[auto-found] source=${c.source} fit=${c.reel_fit} age=${c.age_label || '?'}${views} ${c.url || ''}`.slice(0, 480),
      'YouTube URL': c.source === 'youtube' ? (c.url || '') : '',
      'Status': 'Draft',
      'Post Type': 'reel',
      'Slide Content': 'reel',
      'Reel Fit': c.reel_fit != null ? c.reel_fit : ''
    }
  };
});

// Runs once for ALL appended rows -> builds a single summary email.
// Rows are written 'Draft' (the review gate) -- the builder ignores Drafts, so
// nothing builds until the user flips the good ones to 'Ready to Run'.
const rows = $input.all().map(i => i.json).filter(Boolean);
const count = rows.length;
const sheetUrl = 'https://docs.google.com/spreadsheets/d/13AEU80ULx2Lxnq9SWDeSSFN7unfhr-x_mPyi37oz7O4/edit';

const list = rows
  .map((r, i) => {
    const ctx = r['Enriched Context'] || '';
    const am = /age=(\S+)/.exec(ctx);
    const vm = /views=(\S+)/.exec(ctx);
    const age = am && am[1] !== '?' ? `, ${am[1]} old` : '';
    const views = vm ? `, ${vm[1]} views` : '';
    return `${i + 1}. ${r.Topic || '(untitled)'}  [fit ${r['Reel Fit'] != null ? r['Reel Fit'] : '?'}${age}${views}]`;
  })
  .join('\n');

const subject = `${count} new AI reel topic${count === 1 ? '' : 's'} found - review to build`;
const body = `The Topic Finder added ${count} topic${count === 1 ? '' : 's'} to the Reels tab as 'Draft'.\n\n${list}\n\nEvery topic is on-niche (an AI tool + something you can DO with it), at most 7 days old, deduped against everything already on the sheet, and (for YouTube) backed by a video with 5,000+ views -- so re-running finds NEW, proven topics, not last time's.\n\nNothing builds yet. Open the Reels tab, look these over, and change Status from 'Draft' to 'Ready to Run' on the ones you want made. The reel builder (Workflow B) then picks up ONLY those and renders them (capped to one reel/day). Leave a row on 'Draft' to skip it.\n\nReels tab:\n${sheetUrl}`;

return [{ json: { subject, body, count } }];
